// Filter for image files and select random one
const imageExtensions = ['jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp', 'tiff', 'svg'];
const imageMimeTypes = [
  'image/jpeg',
  'image/png', 
  'image/gif',
  'image/webp',
  'image/bmp',
  'image/tiff',
  'image/svg+xml'
];

try {
  // Get all items from Google Drive
  const allFiles = $input.all().map(item => item.json);

  if (!allFiles || allFiles.length === 0) {
    return [{
      json: {
        error: 'No files found in the specified folder',
        success: false
      }
    }];
  }

  // Filter for image files
  const imageFiles = allFiles.filter(file => {
    const fileName = (file.name || '').toLowerCase();
    const mimeType = file.mimeType || '';

    // Check by file extension
    const hasImageExtension = imageExtensions.some(ext => 
      fileName.endsWith('.' + ext)
    );

    // Check by MIME type
    const hasImageMimeType = imageMimeTypes.includes(mimeType);

    return hasImageExtension || hasImageMimeType;
  });

  if (imageFiles.length === 0) {
    return [{
      json: {
        error: 'No image files found in the folder',
        success: false,
        totalFiles: allFiles.length
      }
    }];
  }

  // Select random image
  const randomIndex = Math.floor(Math.random() * imageFiles.length);
  const selectedImage = imageFiles[randomIndex];

  return [{
    json: {
      success: true,
      selectedImage: selectedImage,
      totalImages: imageFiles.length,
      totalFiles: allFiles.length,
      randomIndex: randomIndex
    }
  }];

} catch (error) {
  return [{
    json: {
      error: 'Error processing files: ' + error.message,
      success: false
    }
  }];
}

// Prepare data for Google Sheets
const filterResult = $node['Filter Images & Select Random'].json;
const shareResult = $json;

if (!filterResult.success) {
  return [{
    json: {
      error: filterResult.error,
      success: false
    }
  }];
}

const selectedImage = filterResult.selectedImage;
const shareableLink = shareResult.webViewLink || shareResult.webContentLink || `https://drive.google.com/file/d/${selectedImage.id}/view`;

const timestamp = new Date().toISOString();
const formattedTimestamp = new Date().toLocaleString();

return [{
  json: {
    success: true,
    fileName: selectedImage.name,
    fileId: selectedImage.id,
    shareableLink: shareableLink,
    mimeType: selectedImage.mimeType,
    timestamp: timestamp,
    formattedTimestamp: formattedTimestamp,
    totalImages: filterResult.totalImages,
    // Data for Google Sheets row
    sheetRowData: {
      'Image Name': selectedImage.name,
      'Shareable Link': shareableLink,
      'File ID': selectedImage.id,
      'Date Added': formattedTimestamp,
      'MIME Type': selectedImage.mimeType
    }
  }
}];

parameters.prompt:
Based on the following data, create a friendly response to the user about the random image selection:

Selected Image: {{ $json.fileName }}
Shareable Link: {{ $json.shareableLink }}
Total Images in Folder: {{ $json.totalImages }}
Added to Sheet: {{ $json.formattedTimestamp }}

Create a conversational response that includes:
1. Confirmation that a random image was selected
2. The image name
3. That it was added to the Google Sheet
4. The shareable link

Keep it friendly and helpful.

