const imageExtensions = ['jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp', 'tiff', 'svg'];
const imageMimeTypes = [
  'image/jpeg', 'image/png', 'image/gif', 'image/webp',
  'image/bmp', 'image/tiff', 'image/svg+xml'
];

try {
  // Get files from Google Drive
  const driveFiles = $node['Google Drive - List Folder Files1'].json;
  const allFiles = Array.isArray(driveFiles) ? driveFiles : [driveFiles];

  // Get tracking data from Google Sheets
  const trackingData = $node['Google Sheets - Get Tracking Data'].json;
  const trackingRows = Array.isArray(trackingData) ? trackingData : [];

  console.log('All files found:', allFiles.length);
  console.log('Tracking rows:', trackingRows.length);

  // Filter for image files only
  const imageFiles = allFiles.filter(file => {
    const fileName = (file.name || '').toLowerCase();
    const mimeType = file.mimeType || '';

    const hasImageExtension = imageExtensions.some(ext => 
      fileName.endsWith('.' + ext)
    );
    const hasImageMimeType = imageMimeTypes.includes(mimeType);

    return hasImageExtension || hasImageMimeType;
  });

  if (imageFiles.length === 0) {
    return [{
      json: {
        error: 'No image files found in the folder',
        success: false,
        totalFiles: allFiles.length
      }
    }];
  }

  console.log('Image files found:', imageFiles.length);

  // Create a set of used image IDs from tracking sheet
  const usedImageIds = new Set();
  const usedImageNames = new Set();

  trackingRows.forEach(row => {
    if (row['File ID']) {
      usedImageIds.add(row['File ID']);
    }
    if (row['Image Name']) {
      usedImageNames.add(row['Image Name']);
    }
  });

  console.log('Used image IDs:', usedImageIds.size);

  // Find unused images
  let unusedImages = imageFiles.filter(image => 
    !usedImageIds.has(image.id) && !usedImageNames.has(image.name)
  );

  console.log('Unused images found:', unusedImages.length);

  let cycleReset = false;

  // If no unused images, reset the cycle
  if (unusedImages.length === 0) {
    console.log('All images have been used. Resetting cycle.');
    unusedImages = imageFiles;
    cycleReset = true;
  }

  // Select random image from unused ones
  const randomIndex = Math.floor(Math.random() * unusedImages.length);
  const selectedImage = unusedImages[randomIndex];

  console.log('Selected image:', selectedImage.name);

  return [{
    json: {
      success: true,
      selectedImage: selectedImage,
      totalImages: imageFiles.length,
      usedImagesCount: usedImageIds.size,
      remainingImages: unusedImages.length - 1, // -1 because we're about to use one
      cycleReset: cycleReset,
      randomIndex: randomIndex,
      allImageFiles: imageFiles // Pass all images for potential tracking updates
    }
  }];

} catch (error) {
  console.error('Error in cycle logic:', error);
  return [{
    json: {
      error: 'Error in cycle logic: ' + error.message,
      success: false
    }
  }];
}

